import{_ as o,o as l,c as s,a3 as t}from"./chunks/framework.Daqi0Atb.js";const g=JSON.parse('{"title":"商业机会扫描器 — 实现计划","description":"","frontmatter":{},"headers":[],"relativePath":"superpowers/plans/2026-07-01-business-opportunity-scanner.md","filePath":"superpowers/plans/2026-07-01-business-opportunity-scanner.md"}'),i={name:"superpowers/plans/2026-07-01-business-opportunity-scanner.md"};function r(p,e,c,a,n,d){return l(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="商业机会扫描器-—-实现计划" tabindex="-1">商业机会扫描器 — 实现计划 <a class="header-anchor" href="#商业机会扫描器-—-实现计划" aria-label="Permalink to &quot;商业机会扫描器 — 实现计划&quot;">​</a></h1><blockquote><p>使用子代理驱动开发（subagent-driven-development）逐任务实现此计划。</p></blockquote><p><strong>目标：</strong> 构建一个自动采集多源信息、分析商业可行性的全栈 Web 应用 <strong>架构：</strong> NestJS + MongoDB 后端（含采集和分析），Vue3 + Vite 前端，Bull + Redis 异步队列 <strong>技术栈：</strong> NestJS, Mongoose, Bull, Redis, Playwright, Cheerio, DeepSeek API, Vue3, ECharts</p><hr><h3 id="任务-1-项目脚手架搭建" tabindex="-1">任务 1：项目脚手架搭建 <a class="header-anchor" href="#任务-1-项目脚手架搭建" aria-label="Permalink to &quot;任务 1：项目脚手架搭建&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li><p>创建：<code>server/</code>（NestJS 项目）</p></li><li><p>创建：<code>server/package.json</code></p></li><li><p>创建：<code>client/</code>（Vue3 + Vite 项目）</p></li><li><p>创建：<code>client/package.json</code></p></li><li><p>创建：<code>docker-compose.yml</code>（MongoDB + Redis）</p></li><li><p>[ ] <strong>搭建 NestJS 后端项目</strong> 使用 <code>nest new</code> 或手动创建 NestJS 项目结构，配置 MongoDB 连接（<code>@nestjs/mongoose</code> + <code>mongoose</code>）、Bull（<code>@nestjs/bull</code>）</p></li><li><p>[ ] <strong>搭建 Vue3 + Vite 前端项目</strong> 使用 <code>create-vite</code> 创建 Vue3 + TS 项目，安装 ECharts 依赖</p></li><li><p>[ ] <strong>创建 docker-compose.yml</strong> 包含 <code>mongodb</code> 和 <code>redis</code> 两个 service</p></li><li><p>[ ] <strong>Commit</strong></p></li></ul><h3 id="任务-2-数据模型-mongoose-schemas" tabindex="-1">任务 2：数据模型（Mongoose Schemas） <a class="header-anchor" href="#任务-2-数据模型-mongoose-schemas" aria-label="Permalink to &quot;任务 2：数据模型（Mongoose Schemas）&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li><p>创建：<code>server/src/schemas/project.schema.ts</code></p></li><li><p>创建：<code>server/src/schemas/raw-page.schema.ts</code></p></li><li><p>创建：<code>server/src/schemas/analysis-report.schema.ts</code></p></li><li><p>创建：<code>server/src/schemas/source-status.schema.ts</code></p></li><li><p>[ ] <strong>定义 4 个 Schema</strong></p></li></ul><p>根据设计文档的数据模型定义，Mongoose Schema + TypeScript 接口。</p><p>关键实现要点：</p><ul><li><p><code>Project</code>：<code>source</code> 枚举 manual/auto，<code>status</code> 枚举 draft/collecting/analyzing/completed/failed</p></li><li><p><code>RawPage</code>：<code>source</code> 枚举 7 个信源，<code>metrics</code> 为混合类型对象</p></li><li><p><code>AnalysisReport</code>：<code>dimensions</code> 下 6 个子维度，每个包含 score(1-10)/analysis/evidence</p></li><li><p><code>SourceStatus</code>：用于采集源健康监控</p></li><li><p>[ ] <strong>Commit</strong></p></li></ul><h3 id="任务-3-后端-rest-api" tabindex="-1">任务 3：后端 REST API <a class="header-anchor" href="#任务-3-后端-rest-api" aria-label="Permalink to &quot;任务 3：后端 REST API&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li><p>创建：<code>server/src/projects/projects.module.ts</code></p></li><li><p>创建：<code>server/src/projects/projects.controller.ts</code></p></li><li><p>创建：<code>server/src/projects/projects.service.ts</code></p></li><li><p>[ ] <strong>实现 API 端点</strong></p></li></ul><table tabindex="0"><thead><tr><th>端点</th><th>方法</th><th>功能</th></tr></thead><tbody><tr><td><code>/api/projects</code></td><td>GET</td><td>项目列表，支持 status/source 筛选、排序、分页</td></tr><tr><td><code>/api/projects</code></td><td>POST</td><td>新增项目（手动输入想法）</td></tr><tr><td><code>/api/projects/:id</code></td><td>GET</td><td>项目详情（含原始数据和报告）</td></tr><tr><td><code>/api/projects/:id</code></td><td>DELETE</td><td>删除项目</td></tr><tr><td><code>/api/projects/:id/analyze</code></td><td>POST</td><td>手动触发分析</td></tr><tr><td><code>/api/sources/status</code></td><td>GET</td><td>各采集源状态</td></tr></tbody></table><ul><li>[ ] <strong>Commit</strong></li></ul><h3 id="任务-4-采集调度系统" tabindex="-1">任务 4：采集调度系统 <a class="header-anchor" href="#任务-4-采集调度系统" aria-label="Permalink to &quot;任务 4：采集调度系统&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li><p>创建：<code>server/src/collector/collector.module.ts</code></p></li><li><p>创建：<code>server/src/collector/collector.service.ts</code></p></li><li><p>创建：<code>server/src/collector/collector.processor.ts</code>（Bull Consumer）</p></li><li><p>创建：<code>server/src/collector/sources/product-hunt.ts</code></p></li><li><p>创建：<code>server/src/collector/sources/github-trending.ts</code></p></li><li><p>创建：<code>server/src/collector/sources/thirty-six-kr.ts</code></p></li><li><p>创建：<code>server/src/collector/sources/hacker-news.ts</code></p></li><li><p>创建：<code>server/src/collector/sources/reddit.ts</code></p></li><li><p>创建：<code>server/src/collector/sources/twitter.ts</code></p></li><li><p>创建：<code>server/src/collector/sources/app-store.ts</code></p></li><li><p>[ ] <strong>实现队列基础设施</strong> Bull Queue 配置，队列名 <code>collection-queue</code>，支持并发控制</p></li><li><p>[ ] <strong>实现 7 个信源 Worker</strong></p></li></ul><p>每个 Worker：</p><ul><li>接收任务类型（<code>source_name</code> + 可选关键词）</li><li>爬取对应源的最新数据</li><li>去重（查 MongoDB 已有 url）</li><li>写入 raw_pages，创建或关联到已有 project</li><li>完成后触发分析队列</li></ul><p>采集方式参考：</p><ul><li><p>Product Hunt：Playwright 打开当日产品页，提取标题/描述/votes</p></li><li><p>GitHub Trending：Playwright 抓 trending 页</p></li><li><p>36氪：Playwright 抓科技快讯列表</p></li><li><p>Hacker News：<code>https://hacker-news.firebaseio.com/v0/topstories.json</code></p></li><li><p>Reddit：<code>https://www.reddit.com/r/SideProject/.rss</code></p></li><li><p>Twitter/X：使用开源 RSS 代理（如 nitter）</p></li><li><p>App Store：<code>https://rss.applemarketingtools.com/api/v2/cn/apps/top-free/50/apps.json</code></p></li><li><p>[ ] <strong>实现 Scheduler</strong> 每天早 8 点 / 晚 8 点触发全源采集（node-cron 或 Bull Queue 的 repeatable job）</p></li><li><p>[ ] <strong>Commit</strong></p></li></ul><h3 id="任务-5-分析评估模块" tabindex="-1">任务 5：分析评估模块 <a class="header-anchor" href="#任务-5-分析评估模块" aria-label="Permalink to &quot;任务 5：分析评估模块&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li><p>创建：<code>server/src/analyzer/analyzer.module.ts</code></p></li><li><p>创建：<code>server/src/analyzer/analyzer.service.ts</code></p></li><li><p>创建：<code>server/src/analyzer/analyzer.processor.ts</code>（Bull Consumer）</p></li><li><p>创建：<code>server/src/analyzer/prompts.ts</code></p></li><li><p>[ ] <strong>实现分析队列</strong></p></li></ul><p>监听 <code>collection-queue</code> 完成事件，自动将新数据入队 <code>analysis-queue</code></p><ul><li>[ ] <strong>实现 LLM 分析服务</strong></li></ul><p>分析 prompt 结构：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是一个商业分析师。分析以下项目信息，从 6 个维度评分（1-10）。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>项目信息：</span></span>
<span class="line"><span>{raw_pages 摘要 + 用户想法}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>维度：</span></span>
<span class="line"><span>1. 市场分析：规模、增长、竞争格局</span></span>
<span class="line"><span>2. 技术实现难度：需要什么技术栈、开发周期</span></span>
<span class="line"><span>3. 商业化潜力：收费模式、目标用户</span></span>
<span class="line"><span>4. 合规风险：国内能不能做、需要什么资质</span></span>
<span class="line"><span>5. 出海可行性：海外市场机会</span></span>
<span class="line"><span>6. 个人开发者友好度：启动成本</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每个维度输出：分数 + 分析理由 + 证据来源引用</span></span>
<span class="line"><span>综合输出：加权总分 + 一句话结论（推荐/观望/不推荐）+ 风险提醒列表</span></span></code></pre></div><ul><li><p>[ ] <strong>实现报告落地</strong> 解析 LLM 返回的 JSON，写入 <code>analysis_reports</code>，更新 <code>project.status = &#39;completed&#39;</code></p></li><li><p>[ ] <strong>Commit</strong></p></li></ul><h3 id="任务-6-前端仪表盘" tabindex="-1">任务 6：前端仪表盘 <a class="header-anchor" href="#任务-6-前端仪表盘" aria-label="Permalink to &quot;任务 6：前端仪表盘&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li><p>创建：<code>client/src/views/Dashboard.vue</code></p></li><li><p>创建：<code>client/src/components/StatCard.vue</code></p></li><li><p>创建：<code>client/src/components/ProjectCard.vue</code></p></li><li><p>创建：<code>client/src/components/RadarChart.vue</code></p></li><li><p>创建：<code>client/src/components/TrendChart.vue</code></p></li><li><p>创建：<code>client/src/components/WordCloud.vue</code></p></li><li><p>创建：<code>client/src/components/SourcePieChart.vue</code></p></li><li><p>创建：<code>client/src/api/index.ts</code></p></li><li><p>[ ] <strong>实现 API 请求层</strong></p></li></ul><p>使用 <code>fetch</code> 或 <code>axios</code> 封装所有后端 API 调用</p><ul><li>[ ] <strong>实现仪表盘页面</strong></li></ul><p>布局：</p><ul><li><p>顶部：搜索框 + &quot;新增想法&quot;按钮 + &quot;刷新采集&quot;按钮</p></li><li><p>统计卡区：总项目 / 本周新增 / 待分析 / 平均分</p></li><li><p>推荐 Top 5：卡片列表，点击进入详情</p></li><li><p>趋势看板（ECharts）：</p><ul><li>雷达图：各维度评分分布（可选项目对比）</li><li>柱状图：每周/月新增项目数</li><li>饼图：各信源采集占比</li><li>词云：热门标签</li></ul></li><li><p>[ ] <strong>Commit</strong></p></li></ul><h3 id="任务-7-前端项目详情页" tabindex="-1">任务 7：前端项目详情页 <a class="header-anchor" href="#任务-7-前端项目详情页" aria-label="Permalink to &quot;任务 7：前端项目详情页&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li><p>创建：<code>client/src/views/ProjectDetail.vue</code></p></li><li><p>[ ] <strong>实现详情页</strong></p></li></ul><p>布局：</p><ul><li><p>项目标题 + 来源标签 + 采集时间</p></li><li><p>综合评分大数字 + 结论标签（推荐/观望/不推荐）</p></li><li><p>风险提醒（红色警告条）</p></li><li><p>六维评分柱状图（每个维度横向柱 + 分数数字）</p></li><li><p>可展开的分析详情（点击维度展开 LLM 分析正文 + 引用来源）</p></li><li><p>原始采集数据列表（标题/来源/链接/摘要）</p></li><li><p>[ ] <strong>Commit</strong></p></li></ul><h3 id="任务-8-前端项目管理页" tabindex="-1">任务 8：前端项目管理页 <a class="header-anchor" href="#任务-8-前端项目管理页" aria-label="Permalink to &quot;任务 8：前端项目管理页&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li><p>创建：<code>client/src/views/ProjectList.vue</code></p></li><li><p>[ ] <strong>实现列表页</strong></p></li></ul><p>布局：</p><ul><li><p>&quot;新增想法&quot;按钮 + &quot;批量分析&quot;</p></li><li><p>筛选标签：全部/待采集/待分析/已完成/失败</p></li><li><p>排序：综合评分/来源/时间</p></li><li><p>项目列表行：标题、评分、状态标签、时间、操作（删除/重分析）</p></li><li><p>[ ] <strong>Commit</strong></p></li></ul><h3 id="任务-9-新增想法对话框-手动触发采集" tabindex="-1">任务 9：新增想法对话框 + 手动触发采集 <a class="header-anchor" href="#任务-9-新增想法对话框-手动触发采集" aria-label="Permalink to &quot;任务 9：新增想法对话框 + 手动触发采集&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li><p>创建：<code>client/src/components/NewProjectDialog.vue</code></p></li><li><p>修改：<code>server/src/projects/projects.service.ts</code></p></li><li><p>[ ] <strong>实现新增想法的对话框/页面</strong></p></li></ul><p>表单字段：</p><ul><li>项目标题（必填）</li><li>项目描述（必填）</li><li>可选补充信息（已有竞品链接、目标用户等）</li></ul><p>提交后：</p><ul><li><p>创建 project（status: collecting）</p></li><li><p>入队采集队列（从用户提供的链接或自动搜索相关话题）</p></li><li><p>前端轮询等待分析完成或 WebSocket 通知</p></li><li><p>[ ] <strong>Commit</strong></p></li></ul><h3 id="任务-10-部署配置" tabindex="-1">任务 10：部署配置 <a class="header-anchor" href="#任务-10-部署配置" aria-label="Permalink to &quot;任务 10：部署配置&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li><p>创建：<code>server/Dockerfile</code></p></li><li><p>创建：<code>server/.env.example</code></p></li><li><p>创建：<code>client/.env.example</code></p></li><li><p>修改：根目录 <code>vercel.json</code></p></li><li><p>[ ] <strong>配置部署</strong></p></li></ul><p>后端：</p><ul><li>Dockerfile 构建 NestJS 应用</li><li>环境变量：MongoDB URI、Redis URI、DeepSeek API Key</li><li>部署到 2C4G 服务器（docker-compose 启动）</li></ul><p>前端：</p><ul><li><p>在现有 <code>vercel.json</code> 中为前端客户端添加配置</p></li><li><p>或单独部署到 Vercel，API 地址通过环境变量配置</p></li><li><p>[ ] <strong>Commit</strong></p></li></ul><hr><h2 id="快速自检" tabindex="-1">快速自检 <a class="header-anchor" href="#快速自检" aria-label="Permalink to &quot;快速自检&quot;">​</a></h2><ul><li>[x] 规格覆盖：仪表盘 + 项目详情 + 项目管理 + 采集 + 分析</li><li>[x] 类型一致：跨任务引用的 API 端点、模型字段一致</li><li>[x] 无占位符：所有文件路径、测试场景、实现要点具体明确</li></ul>`,67)])])}const h=o(i,[["render",r]]);export{g as __pageData,h as default};
